/**
 * Search Results Parser
 * Parses Gemini API response into structured FileSearchResult
 */

import { logger } from '@/server/lib/logger';
import type { FileSearchResult } from '@/types/gemini';
import type { Manifest, ManifestFile, ParsedSearchResult } from './types';

/**
 * Parse search results from Gemini response text
 */
export function parseSearchResults(responseText: string, manifest: Manifest): FileSearchResult[] {
  try {
    // Remove markdown code blocks
    const cleanText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '');
    const jsonMatch = cleanText.match(/\[[\s\S]*\]/);

    if (!jsonMatch) {
      logger.warn('No JSON array found in response');
      return [];
    }

    const results: ParsedSearchResult[] = JSON.parse(jsonMatch[0]);
    if (!Array.isArray(results)) {
      return [];
    }

    // Build category to URL mapping
    const categoryToUrl = buildCategoryUrlMap(manifest.files);

    return results.map(r => mapToFileSearchResult(r, categoryToUrl));
  } catch (error) {
    logger.error({ error }, 'Failed to parse search results');
    return [];
  }
}

/**
 * Build a map from category to URL
 */
function buildCategoryUrlMap(files: ManifestFile[]): Map<string, string> {
  const categoryToUrl = new Map<string, string>();

  files.forEach(file => {
    if (file.category && file.url) {
      categoryToUrl.set(file.category, file.url);
    }
  });

  return categoryToUrl;
}

/**
 * Map parsed result to FileSearchResult
 */
function mapToFileSearchResult(
  result: ParsedSearchResult,
  categoryToUrl: Map<string, string>
): FileSearchResult {
  const category = result.category || (result.source_type === 'web' ? 'トップページ' : 'Q&A');
  const url = categoryToUrl.get(category) || 'https://wmg2027.jp/';

  return {
    text: result.answer || '',
    original_question: result.original_question || result.question || '',
    display_name: result.source_type === 'web' ? '公式サイト' : 'Q&Aデータ',
    uri: url,
    source_type: (result.source_type as 'qa' | 'web') || 'qa',
    category: category,
    locale: 'ja',
    relevance: result.relevance as 'high' | 'medium' | 'low' | undefined,
  };
}

/**
 * Get fallback context when search fails or returns no results
 */
export function getFallbackContext(): FileSearchResult[] {
  return [
    {
      text: 'この質問に関する具体的な情報は見つかりませんでした。ワールドマスターズゲームズ2027に関する詳細情報は、公式サイトをご確認ください。',
      display_name: '公式サイト案内',
      uri: 'https://wmg2027.jp/',
      source_type: 'web',
      locale: 'ja',
    },
  ];
}

