/**
 * Unit Test: PromptTemplateEngine
 * タスク6.1: サーバサイド単体テスト
 */

import { describe, it, expect } from 'vitest';
import { buildPrompt, buildSystemPrompt } from '@/server/lib/prompts/template-engine';
import type { FileSearchResult } from '@/types/gemini';

describe('PromptTemplateEngine', () => {
  describe('buildPrompt', () => {
    it('日本語質問に日本語ルールを適用', () => {
      const userQuery = '参加資格は？';
      const contexts: FileSearchResult[] = [];
      const locale = 'ja';

      const prompt = buildPrompt(userQuery, contexts, locale);

      expect(prompt).toContain('ワールドマスターズゲームズ2027');
      expect(prompt).toContain('公式AIアシスタント');
      expect(prompt).toContain('言語対応ルール');
      expect(prompt).toContain('ロケール設定（ja）を使用');
      expect(prompt).toContain('ユーザーの質問: 参加資格は？');
    });

    it('英語質問に英語ルールを適用', () => {
      const userQuery = 'What are the eligibility requirements?';
      const contexts: FileSearchResult[] = [];
      const locale = 'en';

      const prompt = buildPrompt(userQuery, contexts, locale);

      expect(prompt).toContain('ワールドマスターズゲームズ2027');
      expect(prompt).toContain('公式AIアシスタント');
      expect(prompt).toContain('言語対応ルール');
      expect(prompt).toContain('ロケール設定（en）を使用');
      expect(prompt).toContain('ユーザーの質問: What are the eligibility requirements?');
    });

    it('コンテキストなしの場合はフォールバック文言を含む', () => {
      const userQuery = '参加資格は？';
      const contexts: FileSearchResult[] = [];
      const locale = 'ja';

      const prompt = buildPrompt(userQuery, contexts, locale);

      expect(prompt).toContain('参考情報');
      expect(prompt).toContain('利用可能な参考情報がありません');
      expect(prompt).toContain('回答ルール');
      expect(prompt).toContain('公式サイト');
    });

    it('コンテキストを挿入してプロンプトを生成', () => {
      const userQuery = '参加資格は？';
      const contexts: FileSearchResult[] = [
        {
          text: '参加資格は30歳以上です。',
          display_name: 'コールセンターお問い合わせ履歴_251121除外.json',
          uri: 'files/xxx',
          source_type: 'qa',
          category: '参加資格',
          locale: 'ja',
        },
        {
          text: '年齢制限は各競技により異なります。',
          display_name: 'WMG2027公式サイト',
          uri: 'https://wmg2027.jp/',
          source_type: 'web',
          category: '参加資格',
          locale: 'ja',
        },
      ];
      const locale = 'ja';

      const prompt = buildPrompt(userQuery, contexts, locale);

      expect(prompt).toContain('参考情報 1');
      expect(prompt).toContain('カテゴリ: 参加資格');
      expect(prompt).toContain('ページURL: files/xxx');
      expect(prompt).toContain('内容: 参加資格は30歳以上です。');
      expect(prompt).toContain('参考情報 2');
      expect(prompt).toContain('ページURL: https://wmg2027.jp/');
      expect(prompt).toContain('内容: 年齢制限は各競技により異なります。');
    });

    it('Top3コンテキストが正しくフォーマットされる', () => {
      const userQuery = '開催場所はどこですか？';
      const contexts: FileSearchResult[] = [
        {
          text: '大阪で開催されます。',
          display_name: 'FAQ1.json',
          uri: 'files/aaa',
          source_type: 'qa',
          category: '開催場所',
        },
        {
          text: '関西エリア（大阪・京都・兵庫・滋賀）で開催されます。',
          display_name: 'FAQ2.json',
          uri: 'files/bbb',
          source_type: 'qa',
        },
        {
          text: 'ワールドマスターズゲームズ2027は関西で開催される国際スポーツ大会です。',
          display_name: 'Web3.md',
          uri: 'https://example.com/wmg',
          source_type: 'web',
          locale: 'ja',
        },
      ];
      const locale = 'ja';

      const prompt = buildPrompt(userQuery, contexts, locale);

      expect(prompt).toContain('参考情報 1');
      expect(prompt).toContain('参考情報 2');
      expect(prompt).toContain('参考情報 3');
      expect(prompt).toContain('カテゴリ: 開催場所');
      expect(prompt).toContain('カテゴリ: 未分類');
    });

    it('中国語ロケールが正しく設定される', () => {
      const userQuery = '参加资格是什么？';
      const contexts: FileSearchResult[] = [];
      const locale = 'zh';

      const prompt = buildPrompt(userQuery, contexts, locale);

      expect(prompt).toContain('ロケール設定（zh）を使用');
    });

    it('韓国語ロケールが正しく設定される', () => {
      const userQuery = '참가 자격은 무엇입니까?';
      const contexts: FileSearchResult[] = [];
      const locale = 'ko';

      const prompt = buildPrompt(userQuery, contexts, locale);

      expect(prompt).toContain('ロケール設定（ko）を使用');
    });

    it('回答ルールが含まれる', () => {
      const userQuery = 'テスト質問';
      const contexts: FileSearchResult[] = [];
      const locale = 'ja';

      const prompt = buildPrompt(userQuery, contexts, locale);

      expect(prompt).toContain('回答ルール');
      expect(prompt).toContain('基本原則');
      expect(prompt).toContain('正確性優先');
      expect(prompt).toContain('不明情報の対応');
      expect(prompt).toContain('禁止事項');
      expect(prompt).toContain('個人情報');
    });

    it('回答フォーマットに絵文字見出しガイドラインが含まれる', () => {
      const prompt = buildPrompt('テスト', [], 'ja');

      expect(prompt).toContain('見出しと装飾');
      expect(prompt).toContain('🥇'); // ポイント
      expect(prompt).toContain('🎯'); // おすすめ
      expect(prompt).toContain('💡'); // 次のステップ
      expect(prompt).toContain('🔰'); // 初心者向け
      expect(prompt).toContain('フォローアップ');
    });

    it('Few-shot応答例が含まれる', () => {
      const prompt = buildPrompt('テスト', [], 'ja');

      expect(prompt).toContain('応答例');
      expect(prompt).toContain('例1:');
      expect(prompt).toContain('例2:');
      expect(prompt).toContain('良い応答');
    });

    it('柔軟な対応ルールが含まれる', () => {
      const prompt = buildPrompt('テスト', [], 'ja');

      expect(prompt).toContain('柔軟な対応');
      expect(prompt).toContain('一般的な知識で回答できる質問');
    });
  });

  describe('buildSystemPrompt', () => {
    it('システムプロンプトを正しく構築する', () => {
      const contexts: FileSearchResult[] = [];
      const locale = 'ja';

      const systemPrompt = buildSystemPrompt(contexts, locale);

      expect(systemPrompt).toContain('ワールドマスターズゲームズ2027');
      expect(systemPrompt).toContain('公式AIアシスタント');
      expect(systemPrompt).toContain('言語対応ルール');
      expect(systemPrompt).toContain('回答ルール');
      // ユーザーの質問は含まれない
      expect(systemPrompt).not.toContain('ユーザーの質問:');
    });

    it('コンテキスト付きでシステムプロンプトを構築する', () => {
      const contexts: FileSearchResult[] = [
        {
          text: '参加資格は30歳以上です。',
          display_name: 'FAQ.json',
          uri: 'files/xxx',
          source_type: 'qa',
          category: '参加資格',
        },
      ];
      const locale = 'en';

      const systemPrompt = buildSystemPrompt(contexts, locale);

      expect(systemPrompt).toContain('参考情報 1');
      expect(systemPrompt).toContain('カテゴリ: 参加資格');
      expect(systemPrompt).toContain('ロケール設定（en）を使用');
    });
  });
});

