/**
 * Gemini Gateway Consistency Tests
 * Issue #148: Response consistency improvement
 *
 * Tests for verifying that identical inputs produce consistent outputs.
 */

import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import type { CoreMessage } from 'ai';

// Mock dependencies
vi.mock('@ai-sdk/google', () => ({
  createGoogleGenerativeAI: vi.fn(),
}));

vi.mock('ai', () => ({
  streamText: vi.fn(),
}));

vi.mock('@/server/lib/logger', () => ({
  logger: {
    info: vi.fn(),
    error: vi.fn(),
  },
}));

vi.mock('@/server/lib/gemini/config', () => ({
  getGeminiApiKey: vi.fn(),
  getModelId: vi.fn((model: string) => model),
}));

describe('Gemini Gateway - Response Consistency', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.resetModules();
    vi.useRealTimers();
  });

  describe('Temperature Configuration', () => {
    it('should use temperature=0.3 by default for FAQ consistency', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);
      vi.mocked(streamText).mockResolvedValue({
        toDataStreamResponse: () => new Response(),
      } as any);

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const messages: CoreMessage[] = [{ role: 'user', content: 'WMG2027の参加資格は？' }];

      await generateStreamingResponse(messages);

      // Verify temperature=0.3 is used (Issue #148 fix)
      expect(streamText).toHaveBeenCalledWith(
        expect.objectContaining({
          temperature: 0.3,
        })
      );
    });
  });

  describe('Input Consistency', () => {
    it('should call streamText with identical arguments for identical inputs', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);
      vi.mocked(streamText).mockResolvedValue({
        toDataStreamResponse: () => new Response(),
      } as any);

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const messages: CoreMessage[] = [
        { role: 'system', content: 'You are WMG2027 assistant.' },
        { role: 'user', content: '大阪市で競技は実施されますか？' },
      ];

      // Call 3 times with identical input
      await generateStreamingResponse(messages);
      await generateStreamingResponse(messages);
      await generateStreamingResponse(messages);

      expect(streamText).toHaveBeenCalledTimes(3);

      // Verify all calls received identical arguments
      const calls = vi.mocked(streamText).mock.calls;
      const firstCallArgs = calls[0][0];
      const secondCallArgs = calls[1][0];
      const thirdCallArgs = calls[2][0];

      expect(firstCallArgs.messages).toEqual(secondCallArgs.messages);
      expect(firstCallArgs.messages).toEqual(thirdCallArgs.messages);
      expect(firstCallArgs.temperature).toEqual(secondCallArgs.temperature);
      expect(firstCallArgs.temperature).toEqual(thirdCallArgs.temperature);
      expect(firstCallArgs.maxTokens).toEqual(secondCallArgs.maxTokens);
      expect(firstCallArgs.maxTokens).toEqual(thirdCallArgs.maxTokens);
    });

    it('should maintain consistent context through message history', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);
      vi.mocked(streamText).mockResolvedValue({
        toDataStreamResponse: () => new Response(),
      } as any);

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const conversationHistory: CoreMessage[] = [
        { role: 'system', content: 'You are WMG2027 assistant.' },
        { role: 'user', content: '参加資格は？' },
        { role: 'assistant', content: '30歳以上であれば参加できます。' },
        { role: 'user', content: 'どの競技がおすすめですか？' },
      ];

      // Call twice with same conversation history
      await generateStreamingResponse(conversationHistory);
      await generateStreamingResponse(conversationHistory);

      const calls = vi.mocked(streamText).mock.calls;

      // Verify message history is preserved identically
      expect(calls[0][0].messages).toEqual(calls[1][0].messages);
      expect(calls[0][0].messages).toHaveLength(4);
    });
  });

  describe('Deterministic Configuration', () => {
    it('should use consistent default configuration', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);
      vi.mocked(streamText).mockResolvedValue({
        toDataStreamResponse: () => new Response(),
      } as any);

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const messages: CoreMessage[] = [{ role: 'user', content: 'Test' }];

      await generateStreamingResponse(messages);

      // Verify default config values are used consistently
      expect(streamText).toHaveBeenCalledWith(
        expect.objectContaining({
          temperature: 0.3, // Issue #148: Changed from 0.5 to 0.3
          maxTokens: 2048,
        })
      );
    });
  });
});

